class Solution:
    def minimumLength(self, s: str) -> int:
        while len(s) >= 2 and s[0] == s[-1]:
            c = s[0]
            while s and s[0] == c:
                s = s[1:]
            while s and s[-1] == c:
                s = s[:-1]
        return len(s)
